SELECT COUNT(DISTINCT user_id) AS unique_users
FROM indicator_access_logs
WHERE indicator_id = 1;

SELECT COUNT(indicator_id) AS num_indicators
FROM health_indicators
WHERE theme = 'Reproductive Healthcare';

SELECT COUNT(*) AS access_count
FROM indicator_access_logs
WHERE indicator_id = 1;

SELECT subtheme, valence
FROM health_indicators
WHERE subtheme = 'Access to Abortions' AND valence = 'positive';

SELECT COUNT(*) AS count_of_indicators
FROM health_indicators hi
WHERE hi.theme = 'Maternal Health' AND hi.valence = 'pos';

SELECT COUNT(indicator_id) AS count_of_indicators
FROM health_indicators
WHERE theme = 'Maternal Health';
